84	// this will get time information and return it in timeval, simulating gettimeofday()
85	int gettimeofday(struct timeval *tv, struct timezone *tz)
86	{
87		LARGE_INTEGER counter;
88		LARGE_INTEGER freq;
89	
90		QueryPerformanceFrequency(&freq);
91		QueryPerformanceCounter(&counter);
92	
93		counter.QuadPart *= 1'000'000;
94		counter.QuadPart /= freq.QuadPart;
95	
96		tv->tv_sec = long(counter.QuadPart / 1000000);
97		tv->tv_usec = counter.QuadPart % 1'000'000;
98	
99		return 0;
100	}
