103	static void logv_string(std::string_view format, std::string str) {
104		size_t remove_leading = 0;
105		while (format.size() > 1 && format[0] == '\n') {
106			logv_string("\n", "\n");
107			format = format.substr(1);
108			++remove_leading;
109		}
110		if (remove_leading > 0) {
111			str = str.substr(remove_leading);
112		}
113	
114		if (str.empty())
115			return;
116	
117		size_t nnl_pos = str.find_last_not_of('\n');
118		if (nnl_pos == std::string::npos)
119			log_newline_count += GetSize(str);
120		else
121			log_newline_count = GetSize(str) - nnl_pos - 1;
122	
123		if (log_hasher)
124			log_hasher->update(str);
125	
126		if (log_time)
127		{
128			std::string time_str;
129	
130			if (next_print_log || initial_tv.tv_sec == 0) {
131				next_print_log = false;
132				struct timeval tv;
133				gettimeofday(&tv, NULL);
134				if (initial_tv.tv_sec == 0)
135					initial_tv = tv;
136				if (tv.tv_usec < initial_tv.tv_usec) {
137					tv.tv_sec--;
138					tv.tv_usec += 1'000'000;
139				}
140				tv.tv_sec -= initial_tv.tv_sec;
141				tv.tv_usec -= initial_tv.tv_usec;
142				time_str += stringf("[%05d.%06d] ", int(tv.tv_sec), int(tv.tv_usec));
143			}
144	
145			if (!format.empty() && format[format.size() - 1] == '\n')
146				next_print_log = true;
147	
148			// Special case to detect newlines in Python log output, since
149			// the binding always calls `log("%s", payload)` and the newline
150			// is then in the first formatted argument
151			if (format == "%s" && str.back() == '\n')
152				next_print_log = true;
153	
154			for (auto f : log_files)
155				fputs(time_str.c_str(), f);
156	
157			for (auto f : log_streams)
158				*f << time_str;
159		}
160	
161		for (auto f : log_files)
162			fputs(str.c_str(), f);
163	
164		for (auto f : log_streams)
165			*f << str;
166	
167		RTLIL::Design *design = yosys_get_design();
168		if (design != nullptr)
169			for (auto &scratchpad : log_scratchpads)
170				design->scratchpad[scratchpad].append(str);
171	
172		static std::string linebuffer;
173		static bool log_warn_regex_recusion_guard = false;
174	
175		if (!log_warn_regex_recusion_guard)
176		{
177			log_warn_regex_recusion_guard = true;
178	
179			if (log_warn_regexes.empty() && log_expect_log.empty() && log_expect_prefix_log.empty())
180			{
181				linebuffer.clear();
182			}
183			else
184			{
185				linebuffer += str;
186	
187				if (!linebuffer.empty() && linebuffer.back() == '\n') {
188					for (auto &re : log_warn_regexes)
189						if (std::regex_search(linebuffer, re))
190							log_warning("Found log message matching -W regex:\n%s", str);
191	
192					for (auto &[_, item] : log_expect_log)
193						if (std::regex_search(linebuffer, item.pattern))
194							item.current_count++;
195	
196					linebuffer.clear();
197				}
198			}
199	
200			log_warn_regex_recusion_guard = false;
201		}
202	}
