544	
545		if ((p = __builtin_extract_return_addr(__builtin_return_address(8))) && dladdr(p, &dli)) {
546			log("%sframe #9: %p %s(%p) %s(%p)\n", prefix, p, dli.dli_fname, dli.dli_fbase, dli.dli_sname, dli.dli_saddr);
547		} else {
548			log("%sframe #9: ---\n", prefix);
549			return;
550		}
551	
552		if (levels <= 9) return;
553	#endif
554	}
555	#else
556	void log_backtrace(const char*, int) { }
557	#endif
558	
559	void log_reset_stack()
560	{
561		while (header_count.size() > 1)
562			header_count.pop_back();
563		log_id_cache_clear();
564		log_flush();
565	}
566	
567	void log_flush()
568	{
569		for (auto f : log_files)
570			fflush(f);
571	
572		for (auto f : log_streams)
573			f->flush();
574	}
575	
576	void log_dump_val_worker(RTLIL::IdString v) {
577		log("%s", v.unescape());
578	}
579	
580	void log_dump_val_worker(RTLIL::SigSpec v) {
581		log("%s", log_signal(v));
582	}
583	
584	void log_dump_val_worker(RTLIL::State v) {
585		log("%s", log_signal(v));
586	}
587	
588	std::string log_signal(const RTLIL::SigSpec &sig, bool autoint)
589	{
590		std::stringstream buf;
591		RTLIL_BACKEND::dump_sigspec(buf, sig, autoint);
592		return buf.str();
593	}
594	
595	std::string log_const(const RTLIL::Const &value, bool autoint)
596	{
597		if ((value.flags & RTLIL::CONST_FLAG_STRING) == 0)
598			return log_signal(value, autoint);
599	
600		return "\"" + value.decode_string() + "\"";
601	}
602	
603	const char *log_id(const RTLIL::IdString &str)
604	{
605		std::string unescaped = str.unescape();
606		log_id_cache.push_back(strdup(unescaped.c_str()));
607		return log_id_cache.back();
608	}
609	
610	void log_module(RTLIL::Module *module, std::string indent)
611	{
612		std::stringstream buf;
613		RTLIL_BACKEND::dump_module(buf, indent, module, module->design, false);
614		log("%s", buf.str());
615	}
616	
617	void log_cell(RTLIL::Cell *cell, std::string indent)
618	{
619		std::stringstream buf;
620		RTLIL_BACKEND::dump_cell(buf, indent, cell);
621		log("%s", buf.str());
622	}
623	
624	void log_wire(RTLIL::Wire *wire, std::string indent)
625	{
626		std::stringstream buf;
627		RTLIL_BACKEND::dump_wire(buf, indent, wire);
628		log("%s", buf.str());
629	}
630	
631	void log_check_expected()
632	{
633		// copy out all of the expected logs so that they cannot be re-checked
634		// or match against themselves
635		dict<std::string, LogExpectedItem> expect_log, expect_warning, expect_error;
636		dict<std::string, LogExpectedItem> expect_prefix_log, expect_prefix_warning, expect_prefix_error;
637		std::swap(expect_warning, log_expect_warning);
638		std::swap(expect_log, log_expect_log);
639		std::swap(expect_error, log_expect_error);
640		std::swap(expect_prefix_warning, log_expect_prefix_warning);
641		std::swap(expect_prefix_log, log_expect_prefix_log);
642		std::swap(expect_prefix_error, log_expect_prefix_error);
643	
644		auto check = [&](const std::string kind, std::string pattern, LogExpectedItem item) {
645			if (item.current_count == 0) {
646				log_warn_regexes.clear();
647				log_error("Expected %s pattern '%s' not found !\n", kind, pattern);
648			}
649			if (item.current_count != item.expected_count) {
650				log_warn_regexes.clear();
651				log_error("Expected %s pattern '%s' found %d time(s), instead of %d time(s) !\n",
652					kind.c_str(), pattern.c_str(), item.current_count, item.expected_count);
653			}
654		};
655	
656		for (auto &[pattern, item] : expect_warning)
657			check("warning", pattern, item);
658		for (auto &[pattern, item] : expect_prefix_warning)
659			check("prefixed warning", pattern, item);
660		for (auto &[pattern, item] : expect_log)
661			check("log", pattern, item);
662		for (auto &[pattern, item] : expect_prefix_log)
663			check("prefixed log", pattern, item);
664	
665		auto check_err = [&](const std::string kind, std::string pattern, LogExpectedItem item) {
666			if (item.current_count == item.expected_count) {
667				log_warn_regexes.clear();
668				log("Expected %s pattern '%s' found !!!\n", kind, pattern);
669				yosys_shutdown();
670				#if defined(_MSC_VER)
671					_exit(0);
672				#else
673					_Exit(0);
674				#endif
675			} else {
676				log_warn_regexes.clear();
677				log_error("Expected %s pattern '%s' not found !\n", kind, pattern);
678			}
679		};
680		for (auto &[pattern, item] : expect_error)
681			check_err("error", pattern, item);
682		for (auto &[pattern, item] : expect_prefix_error)
683			check_err("prefixed error", pattern, item);
684	}
685	
686	YOSYS_NAMESPACE_END
